code.Java:
public class Main {
  public static void main(String[] args) {
    int T, N, K, i, gcd;
    java.util.Scanner sc = new java.util.Scanner(System.in);
    T = sc.nextInt();
    while (T-- > 0) {
      N = sc.nextInt();
      K = sc.nextInt();
      gcd = 0;
      for (i = 1; i <= K; i++) {
        gcd = gcd(gcd, N % i == 0 ? i : N / i);
      }
      System.out.println(gcd);
    }
  }
  public static int gcd(int a, int b) {
    return b == 0 ? a : gcd(b, a % b);
  }
}

code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
const lines = readline[Symbol.asyncIterator]().next().value.trim().split('\n');
(async () => {
  const T = parseInt(lines.shift());
  for (let i = 0; i < T; i++) {
    const [N, K] = lines.shift().split(' ').map(Number);
    let gcd = 0;
    for (let j = 1; j <= K; j++) {
      gcd = gcd(gcd, N % j == 0 ? j : Math.floor(N / j));
    }
    console.log(gcd);
  }
  function gcd(a, b) {
    return b == 0 ? a : gcd(b, a % b);
  }
})().then(() => readline.close());
